create type public.short_link_status as enum ('active','disabled','blocked','expired','deleted');
create type public.app_role as enum ('super_admin','admin','analyst');
create table public.profiles(id uuid primary key references auth.users on delete cascade, role public.app_role not null default 'analyst', created_at timestamptz not null default now());
create table public.short_links(id uuid primary key default gen_random_uuid(),slug varchar(32) unique not null check(slug ~ '^[A-Za-z0-9]{8,32}$'),destination_url text not null check(destination_url like 'https://wa.me/%'),destination_type text not null default 'whatsapp' check(destination_type='whatsapp'),status public.short_link_status not null default 'active',created_by uuid references auth.users,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),expires_at timestamptz,last_accessed_at timestamptz,click_count bigint not null default 0,deleted_at timestamptz,metadata jsonb not null default '{}'::jsonb);
create table public.short_link_clicks(id uuid primary key default gen_random_uuid(),short_link_id uuid not null references public.short_links,clicked_at timestamptz not null default now(),referrer_domain text,device_type text,browser_family text,country_code char(2),ip_hash text,user_agent_hash text,is_bot boolean not null default false);
create table public.short_link_daily_stats(id uuid primary key default gen_random_uuid(),short_link_id uuid not null references public.short_links,date date not null,clicks int not null default 0,unique_click_estimate int not null default 0,bot_clicks int not null default 0,mobile_clicks int not null default 0,desktop_clicks int not null default 0,unknown_device_clicks int not null default 0,unique(short_link_id,date));
create table public.app_settings(key text primary key,value jsonb not null,updated_at timestamptz not null default now());
create table public.audit_logs(id uuid primary key default gen_random_uuid(),actor_user_id uuid references auth.users,action text not null,entity_type text not null,entity_id uuid,before_data jsonb,after_data jsonb,created_at timestamptz not null default now(),ip_hash text);
create table public.abuse_reports(id uuid primary key default gen_random_uuid(),reported_url text not null,reason text not null check(reason in ('spam','phishing','fraude','conteúdo impróprio','outro')),description text,email text,status text not null default 'open',created_at timestamptz not null default now());
create index short_links_status_idx on public.short_links(status);create index short_links_created_idx on public.short_links(created_at);create index short_links_expires_idx on public.short_links(expires_at);create index clicks_link_idx on public.short_link_clicks(short_link_id);create index clicks_date_idx on public.short_link_clicks(clicked_at);
alter table public.profiles enable row level security;alter table public.short_links enable row level security;alter table public.short_link_clicks enable row level security;alter table public.short_link_daily_stats enable row level security;alter table public.app_settings enable row level security;alter table public.audit_logs enable row level security;alter table public.abuse_reports enable row level security;
create or replace function public.resolve_short_link(p_slug text) returns table(id uuid,slug text,destination_url text,status public.short_link_status,expires_at timestamptz) language sql security definer set search_path=public as $$select id,slug,destination_url,status,expires_at from short_links where slug=p_slug and deleted_at is null limit 1$$;
grant execute on function public.resolve_short_link(text) to anon,authenticated;
insert into public.app_settings(key,value) values ('shortener.enabled','true'),('shortener.domain','"https://encurta.io"'),('shortener.slug_length','8'),('shortener.allowed_destination_hosts','["wa.me"]'),('shortener.analytics_enabled','true'),('shortener.creation_enabled','true') on conflict do nothing;
